mapper.select:
SELECT bi.campus as `value`, SUM(CASE WHEN bi.status = 'available' THEN 1 ELSE 0 END) as `count`
FROM book_items bi
LEFT JOIN books b ON bi.bookId = b.id
WHERE bi.campus IS NOT NULL
AND bi.location = #{location}
AND (b.title LIKE CONCAT('%', #{search}, '%') OR b.author LIKE CONCAT('%', #{search}, '%') OR b.isbn LIKE CONCAT('%', #{search}, '%'))
AND b.categoryId = #{categoryId}
AND b.language = #{language}
AND b.year >= #{yearMin}
AND b.year <= #{yearMax}
GROUP BY bi.campus ORDER BY `count` DESC

SELECT bi.location as `value`, SUM(CASE WHEN bi.status = 'available' THEN 1 ELSE 0 END) as `count`
FROM book_items bi
LEFT JOIN books b ON bi.bookId = b.id
WHERE bi.location IS NOT NULL
AND bi.campus = #{campus}
AND (b.title LIKE CONCAT('%', #{search}, '%') OR b.author LIKE CONCAT('%', #{search}, '%') OR b.isbn LIKE CONCAT('%', #{search}, '%'))
AND b.categoryId = #{categoryId}
AND b.language = #{language}
AND b.year >= #{yearMin}
AND b.year <= #{yearMax}
GROUP BY bi.location ORDER BY `count` DESC
